<?php
// Generated by Cursor prompt — Service: HolidayCheckerService — date: 2026-03-15
// Resmi Tatil ve Hafta Sonu Entegrasyonu

namespace App\Services;

use Carbon\Carbon;
use Carbon\CarbonPeriod;
use Illuminate\Support\Facades\DB;
use Illuminate\Support\Facades\Cache;

class HolidayCheckerService
{
    /**
     * Verilen tarih aralığındaki NET iş günü sayısını hesapla.
     * Hafta sonlarını, resmi tatilleri ve izin günlerini çıkarır.
     */
    public function calculateWorkDays(
        string $startDate,
        string $endDate,
        int    $companyId,
        array  $workDays = [1, 2, 3, 4, 5]
    ): array {
        $period   = CarbonPeriod::create($startDate, $endDate);
        $holidays = $this->getHolidays($companyId, $startDate, $endDate);

        $workDayCount    = 0;
        $weekendDays     = 0;
        $holidayDays     = 0;
        $conflictDates   = [];

        foreach ($period as $date) {
            $dayOfWeek = $date->dayOfWeekIso; // 1=Pzt, 7=Paz
            $dateStr   = $date->toDateString();

            if (!in_array($dayOfWeek, $workDays)) {
                $weekendDays++;
                continue;
            }

            if (in_array($dateStr, $holidays)) {
                $holidayDays++;
                $conflictDates[] = ['date' => $dateStr, 'type' => 'holiday', 'name' => $holidays[$dateStr] ?? 'Resmi Tatil'];
                continue;
            }

            $workDayCount++;
        }

        return [
            'total_days'    => iterator_count(CarbonPeriod::create($startDate, $endDate)),
            'work_days'     => $workDayCount,
            'weekend_days'  => $weekendDays,
            'holiday_days'  => $holidayDays,
            'conflicts'     => $conflictDates,
            'has_conflicts' => !empty($conflictDates),
        ];
    }

    /**
     * İzin talebinin hafta sonu veya tatil günlerine denk gelip gelmediğini kontrol et.
     */
    public function validateLeaveRequest(
        string $startDate,
        string $endDate,
        int    $companyId,
        array  $workDays = [1, 2, 3, 4, 5]
    ): array {
        $result = $this->calculateWorkDays($startDate, $endDate, $companyId, $workDays);

        $warnings = [];

        if ($result['weekend_days'] > 0) {
            $warnings[] = "Seçilen tarih aralığında {$result['weekend_days']} hafta sonu günü bulunuyor. Bu günler izin bakiyesinden düşülmeyecektir.";
        }

        if ($result['has_conflicts']) {
            $names = collect($result['conflicts'])->pluck('name')->implode(', ');
            $warnings[] = "Seçilen tarihler şu resmi tatillere denk geliyor: {$names}. Bu günler izin bakiyesinden düşülmeyecektir.";
        }

        if ($result['work_days'] === 0) {
            return [
                'valid'     => false,
                'work_days' => 0,
                'warnings'  => ['Seçilen tarih aralığında hiç iş günü bulunmuyor.'],
                'conflicts' => $result['conflicts'],
            ];
        }

        return [
            'valid'     => true,
            'work_days' => $result['work_days'],
            'warnings'  => $warnings,
            'conflicts' => $result['conflicts'],
            'breakdown' => $result,
        ];
    }

    /**
     * Şirkete + Türkiye geneli tatilleri getir (cache destekli).
     * @return array ['Y-m-d' => 'Tatil Adı']
     */
    public function getHolidays(int $companyId, string $startDate, string $endDate): array
    {
        $cacheKey = "holidays_{$companyId}_{$startDate}_{$endDate}";

        return Cache::remember($cacheKey, now()->addHours(24), function () use ($companyId, $startDate, $endDate) {
            $rows = DB::table('holidays')
                ->where(fn ($q) => $q->where('company_id', $companyId)->orWhereNull('company_id'))
                ->whereBetween('date', [$startDate, $endDate])
                ->get();

            $result = [];
            foreach ($rows as $row) {
                $result[$row->date] = $row->name;
            }
            return $result;
        });
    }

    /**
     * Belirli bir tarihin iş günü olup olmadığını kontrol et.
     */
    public function isWorkDay(string $date, int $companyId, array $workDays = [1, 2, 3, 4, 5]): bool
    {
        $carbon    = Carbon::parse($date);
        $dayOfWeek = $carbon->dayOfWeekIso;

        if (!in_array($dayOfWeek, $workDays)) return false;

        $holidays = $this->getHolidays($companyId, $date, $date);
        return !isset($holidays[$date]);
    }

    /**
     * Türkiye'nin 2025-2026 resmi tatillerini seed et (yardımcı metod).
     */
    public function seedTurkeyHolidays(int $year): void
    {
        $holidays = [
            "{$year}-01-01" => "Yılbaşı",
            "{$year}-04-23" => "Ulusal Egemenlik ve Çocuk Bayramı",
            "{$year}-05-01" => "Emek ve Dayanışma Günü",
            "{$year}-05-19" => "Atatürk'ü Anma, Gençlik ve Spor Bayramı",
            "{$year}-07-15" => "Demokrasi ve Millî Birlik Günü",
            "{$year}-08-30" => "Zafer Bayramı",
            "{$year}-10-29" => "Cumhuriyet Bayramı",
        ];

        foreach ($holidays as $date => $name) {
            DB::table('holidays')->updateOrInsert(
                ['date' => $date, 'country_code' => 'TR', 'is_national' => true],
                ['name' => $name, 'company_id' => null, 'created_at' => now(), 'updated_at' => now()]
            );
        }
    }
}
